1	"use client";
2	
3	import { useEffect, useState } from "react";
4	import Link from "next/link";
5	import { useAuth } from "@/lib/auth-context";
6	import { apiFetch, type PaginatedResponse } from "@/lib/api-client";
7	import { Button } from "@/components/ui/button";
8	
9	interface AssetItem {
10	  id: string;
11	  model?: { modelName: string; brandName: string; category: string };
12	  status: string;
13	  warrantyExpiry: string;
14	}
15	
16	interface TicketItem {
17	  id: string;
18	  type: string;
19	  status: string;
20	  reason: string;
21	  createdAt: string;
22	  targetModel?: { modelName: string };
23	}
24	
25	export default function HomePage() {
26	  const { user } = useAuth();
27	  const [assets, setAssets] = useState<AssetItem[]>([]);
28	  const [tickets, setTickets] = useState<TicketItem[]>([]);
29	  const [loading, setLoading] = useState(true);
30	  const [error, setError] = useState("");
31	
32	  const fetchData = async () => {
33	    setLoading(true);
34	    setError("");
35	    try {
36	      const [assetRes, ticketRes] = await Promise.all([
37	        apiFetch<PaginatedResponse<AssetItem>>("/api/assets/mine", { params: { page: 1, pageSize: 100 } }),
38	        apiFetch<PaginatedResponse<TicketItem>>("/api/tickets", { params: { page: 1, pageSize: 5 } }),
39	      ]);
40	      setAssets(assetRes.data);
41	      setTickets(ticketRes.data);
42	    } catch (err) {
43	      setError(err instanceof Error ? err.message : "加载失败");
44	    } finally {
45	      setLoading(false);
46	    }
47	  };
48	
49	  useEffect(() => {
50	    fetchData();
51	  }, []);
52	
53	  const inUseCount = assets.filter((a) => a.status === "IN_USE" || a.status === "ASSIGNED").length;
54	  const repairCount = assets.filter((a) => a.status === "REPAIRING").length;
55	  const totalCount = assets.length;
56	
57	  if (loading) {
58	    return (
59	      <div className="flex flex-1 items-center justify-center">
60	        <div className="space-y-4 w-full max-w-4xl px-4">
61	          <div className="h-8 w-48 animate-pulse rounded bg-muted" />
62	          <div className="grid grid-cols-3 gap-4">
63	            {[1, 2, 3].map((i) => (
64	              <div key={i} className="h-24 animate-pulse rounded-lg bg-muted" />
65	            ))}
66	          </div>
67	          <div className="h-64 animate-pulse rounded-lg bg-muted" />
68	        </div>
69	      </div>
70	    );
71	  }
72	
73	  if (!user) {
74	    return (
75	      <div className="flex flex-1 items-center justify-center px-4">
76	        <p className="text-muted-foreground">请先登录</p>
77	      </div>
78	    );
79	  }
80	
81	  if (error) {
82	    return (
83	      <div className="flex flex-1 flex-col items-center justify-center gap-4 px-4">
84	        <p className="text-destructive">{error}</p>
85	        <Button onClick={fetchData}>重试</Button>
86	      </div>
87	    );
88	  }
89	
90	  return (
91	    <div className="flex flex-1 flex-col gap-6 p-4 max-w-4xl mx-auto w-full">
92	      <div>
93	        <h1 className="text-2xl font-bold">欢迎, {user.name}</h1>
94	        <p className="text-sm text-muted-foreground">
95	          {user.role === "IT_ADMIN"
96	            ? "IT 管理控制台"
97	            : user.role === "MANAGER"
98	              ? "部门管理面板"
99	              : user.role === "EXECUTIVE"
100	                ? "高管仪表盘"
101	                : "我的工作台"}
102	        </p>
103	      </div>
104	
105	      {/* Stats Cards */}
106	      <div className="grid grid-cols-3 gap-4">
107	        <div className="rounded-lg border p-4">
108	          <p className="text-sm text-muted-foreground">总资产</p>
109	          <p className="text-3xl font-bold">{totalCount}</p>
110	        </div>
111	        <div className="rounded-lg border p-4">
112	          <p className="text-sm text-muted-foreground">使用中</p>
113	          <p className="text-3xl font-bold">{inUseCount}</p>
114	        </div>
115	        <div className="rounded-lg border p-4">
116	          <p className="text-sm text-muted-foreground">维修中</p>
117	          <p className="text-3xl font-bold">{repairCount}</p>
118	        </div>
119	      </div>
120	
121	      {/* Quick Actions */}
122	      <div className="flex flex-wrap gap-2">
123	        <Link href="/my-assets">
124	          <Button variant="outline">我的资产</Button>
125	        </Link>
126	        <Link href="/apply">
127	          <Button variant="outline">申领设备</Button>
128	        </Link>
129	        <Link href="/tickets">
130	          <Button variant="outline">我的工单</Button>
131	        </Link>
132	        <Link href="/chat">
133	          <Button variant="outline">AI 助手</Button>
134	        </Link>
135	        {user.role === "MANAGER" && (
136	          <Link href="/approvals">
137	            <Button variant="outline">待审批</Button>
138	          </Link>
139	        )}
140	        {user.role === "IT_ADMIN" && (
141	          <Link href="/it/home">
142	            <Button variant="outline">IT 管理</Button>
143	          </Link>
144	        )}
145	        {user.role === "EXECUTIVE" && (
146	          <Link href="/exec/dashboard">
147	            <Button variant="outline">数据看板</Button>
148	          </Link>
149	        )}
150	      </div>
151	
152	      {/* Recent Tickets */}
153	      <div>
154	        <div className="flex items-center justify-between mb-3">
155	          <h2 className="text-lg font-semibold">最近工单</h2>
156	          <Link href="/tickets" className="text-sm text-primary underline-offset-4 hover:underline">
157	            查看全部
158	          </Link>
159	        </div>
160	        {tickets.length === 0 ? (
161	          <div className="rounded-lg border border-dashed p-8 text-center text-sm text-muted-foreground">
162	            暂无工单
163	          </div>
164	        ) : (
165	          <div className="space-y-2">
166	            {tickets.map((t) => (
167	              <Link
168	                key={t.id}
169	                href={`/tickets/${t.id}`}
170	                className="block rounded-lg border p-3 transition-colors hover:bg-muted/50"
171	              >
172	                <div className="flex items-center justify-between">
173	                  <span className="font-medium">
174	                    {t.type === "APPLY" ? "申领" : t.type === "REPAIR" ? "报修" : t.type === "RETURN" ? "归还" : "调拨"}{" "}
175	                    {t.targetModel?.modelName ?? ""}
176	                  </span>
177	                  <span className="rounded-full bg-secondary px-2 py-0.5 text-xs">{t.status}</span>
178	                </div>
179	                <p className="mt-1 text-sm text-muted-foreground line-clamp-1">{t.reason}</p>
180	              </Link>
181	            ))}
182	          </div>
183	        )}
184	      </div>
185	    </div>
186	  );
187	}
