1	"use client";
2	
3	import { useState } from "react";
4	import { useRouter } from "next/navigation";
5	import { useAuth } from "@/lib/auth-context";
6	import { Button } from "@/components/ui/button";
7	
8	export default function LoginPage() {
9	  const router = useRouter();
10	  const { login, loginAsDemo } = useAuth();
11	  const [email, setEmail] = useState("");
12	  const [password, setPassword] = useState("");
13	  const [error, setError] = useState("");
14	  const [loading, setLoading] = useState(false);
15	
16	  const handleSubmit = async (e: React.FormEvent) => {
17	    e.preventDefault();
18	    setError("");
19	    if (!email.trim() || !password.trim()) {
20	      setError("请输入邮箱和密码");
21	      return;
22	    }
23	    setLoading(true);
24	    try {
25	      await login(email, password);
26	      router.push("/home");
27	    } catch (err) {
28	      setError(
29	        err instanceof Error ? err.message : "登录失败，请检查邮箱和密码",
30	      );
31	    } finally {
32	      setLoading(false);
33	    }
34	  };
35	
36	  return (
37	    <div className="flex flex-1 items-center justify-center px-4">
38	      <div className="w-full max-w-sm space-y-6">
39	        <div className="text-center">
40	          <h1 className="text-2xl font-bold">IT 资产管理系统</h1>
41	          <p className="mt-1 text-sm text-muted-foreground">请登录以继续</p>
42	        </div>
43	
44	        <form onSubmit={handleSubmit} className="space-y-4">
45	          <div className="space-y-2">
46	            <label htmlFor="email" className="text-sm font-medium">
47	              邮箱
48	            </label>
49	            <input
50	              id="email"
51	              type="email"
52	              value={email}
53	              onChange={(e) => setEmail(e.target.value)}
54	              placeholder="name@example.com"
55	              className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50"
56	              autoComplete="email"
57	            />
58	          </div>
59	
60	          <div className="space-y-2">
61	            <label htmlFor="password" className="text-sm font-medium">
62	              密码
63	            </label>
64	            <input
65	              id="password"
66	              type="password"
67	              value={password}
68	              onChange={(e) => setPassword(e.target.value)}
69	              placeholder="••••••••"
70	              className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50"
71	              autoComplete="current-password"
72	            />
73	          </div>
74	
75	          {error && (
76	            <div className="rounded-lg bg-destructive/10 px-3 py-2 text-sm text-destructive">
77	              {error}
78	            </div>
79	          )}
80	
81	          <Button type="submit" disabled={loading} className="w-full">
82	            {loading ? "登录中..." : "登录"}
83	          </Button>
84	        </form>
85	
86	        <div className="relative my-6">
87	          <div className="absolute inset-0 flex items-center">
88	            <div className="w-full border-t" />
89	          </div>
90	          <div className="relative flex justify-center text-xs uppercase">
91	            <span className="bg-background px-2 text-muted-foreground">或</span>
92	          </div>
93	        </div>
94	
95	        <div className="grid grid-cols-2 gap-2">
96	          <Button
97	            variant="outline"
98	            onClick={() => { loginAsDemo("EMPLOYEE"); router.push("/home"); }}
99	          >
100	            员工演示
101	          </Button>
102	          <Button
103	            variant="outline"
104	            onClick={() => { loginAsDemo("MANAGER"); router.push("/home"); }}
105	          >
106	            主管演示
107	          </Button>
108	          <Button
109	            variant="outline"
110	            onClick={() => { loginAsDemo("IT_ADMIN"); router.push("/home"); }}
111	          >
112	            IT 演示
113	          </Button>
114	          <Button
115	            variant="outline"
116	            onClick={() => { loginAsDemo("EXECUTIVE"); router.push("/home"); }}
117	          >
118	            高管演示
119	          </Button>
120	        </div>
121	      </div>
122	    </div>
123	  );
124	}
