1	"use client";
2	
3	import { useState } from "react";
4	import { useRouter } from "next/navigation";
5	import { useAuth } from "@/lib/auth-context";
6	import { apiFetch } from "@/lib/api-client";
7	import { Button } from "@/components/ui/button";
8	
9	interface Recommendation {
10	  modelId: string;
11	  score: number;
12	  reason: string;
13	}
14	
15	export default function ApplyPage() {
16	  const router = useRouter();
17	  const { user } = useAuth();
18	  const [selectedModelId, setSelectedModelId] = useState("");
19	  const [reason, setReason] = useState("");
20	  const [requirement, setRequirement] = useState("");
21	  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
22	  const [recommending, setRecommending] = useState(false);
23	  const [recommendError, setRecommendError] = useState("");
24	  const [submitting, setSubmitting] = useState(false);
25	  const [submitError, setSubmitError] = useState("");
26	
27	  const handleRecommend = async () => {
28	    if (!requirement.trim()) return;
29	    setRecommending(true);
30	    setRecommendError("");
31	    setRecommendations([]);
32	    try {
33	      type RecommendResponse =
34	        | { ok: true; data: { recommendations: Recommendation[]; topPick: string } }
35	        | { ok: false; fallback: string };
36	      const res = await apiFetch<RecommendResponse>(
37	        "/api/ai/recommend",
38	        { method: "POST", body: { requirement } },
39	      );
40	      if (res.ok) {
41	        setRecommendations(res.data.recommendations);
42	        if (res.data.recommendations.length > 0) {
43	          setSelectedModelId(res.data.recommendations[0].modelId);
44	        }
45	      } else {
46	        setRecommendError(res.fallback);
47	      }
48	    } catch (err) {
49	      setRecommendError(err instanceof Error ? err.message : "推荐失败，请稍后重试");
50	    } finally {
51	      setRecommending(false);
52	    }
53	  };
54	
55	  const handleSubmit = async () => {
56	    if (!selectedModelId || !reason.trim()) return;
57	    setSubmitting(true);
58	    setSubmitError("");
59	    try {
60	      const ticket = await apiFetch<{ id: string }>("/api/tickets/apply", {
61	        method: "POST",
62	        body: { modelId: selectedModelId, reason },
63	      });
64	      router.push(`/tickets/${ticket.id}`);
65	    } catch (err) {
66	      setSubmitError(err instanceof Error ? err.message : "提交失败");
67	    } finally {
68	      setSubmitting(false);
69	    }
70	  };
71	
72	  return (
73	    <div className="flex flex-1 flex-col gap-6 p-4 max-w-2xl mx-auto w-full">
74	      <h1 className="text-2xl font-bold">申领设备</h1>
75	
76	      {/* AI Recommendation */}
77	      <div className="rounded-lg border p-4 space-y-3">
78	        <h2 className="font-semibold">AI 推荐</h2>
79	        <p className="text-sm text-muted-foreground">
80	          描述你的需求，AI 将推荐最适合的设备
81	        </p>
82	        <textarea
83	          value={requirement}
84	          onChange={(e) => setRequirement(e.target.value)}
85	          placeholder="例如：我需要一台用于日常开发的高性能笔记本电脑"
86	          rows={3}
87	          className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50"
88	        />
89	        <Button onClick={handleRecommend} disabled={recommending || !requirement.trim()}>
90	          {recommending ? "推荐中..." : "获取推荐"}
91	        </Button>
92	        {recommendError && (
93	          <p className="text-sm text-destructive">{recommendError}</p>
94	        )}
95	        {recommendations.length > 0 && (
96	          <div className="space-y-2 mt-2">
97	            <p className="text-sm font-medium">推荐结果：</p>
98	            {recommendations.map((r) => (
99	              <label
100	                key={r.modelId}
101	                className={`flex items-start gap-3 rounded-lg border p-3 cursor-pointer transition-colors ${
102	                  selectedModelId === r.modelId ? "border-primary bg-primary/5" : ""
103	                }`}
104	              >
105	                <input
106	                  type="radio"
107	                  name="model"
108	                  value={r.modelId}
109	                  checked={selectedModelId === r.modelId}
110	                  onChange={() => setSelectedModelId(r.modelId)}
111	                  className="mt-1"
112	                />
113	                <div className="flex-1">
114	                  <div className="flex items-center justify-between">
115	                    <span className="font-medium text-sm">型号 ID: {r.modelId}</span>
116	                    <span className="text-sm font-bold text-primary">{r.score}分</span>
117	                  </div>
118	                  <p className="text-sm text-muted-foreground mt-1">{r.reason}</p>
119	                </div>
120	              </label>
121	            ))}
122	          </div>
123	        )}
124	      </div>
125	
126	      {/* Submit Form */}
127	      <div className="rounded-lg border p-4 space-y-3">
128	        <h2 className="font-semibold">提交申请</h2>
129	        <div className="space-y-2">
130	          <label className="text-sm font-medium">选择设备</label>
131	          {recommendations.length === 0 ? (
132	            <div className="space-y-1">
133	              <p className="text-xs text-muted-foreground">
134	                请先使用 AI 推荐获取设备型号，或直接输入型号 ID
135	              </p>
136	              <input
137	                value={selectedModelId}
138	                onChange={(e) => setSelectedModelId(e.target.value)}
139	                placeholder="输入型号 ID"
140	                className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50"
141	              />
142	            </div>
143	          ) : (
144	            <p className="text-sm text-muted-foreground">
145	              已选择推荐列表中的设备
146	            </p>
147	          )}
148	        </div>
149	        <div className="space-y-2">
150	          <label className="text-sm font-medium">申请理由</label>
151	          <textarea
152	            value={reason}
153	            onChange={(e) => setReason(e.target.value)}
154	            placeholder="请说明申请理由..."
155	            rows={3}
156	            className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50"
157	          />
158	        </div>
159	        {submitError && (
160	          <p className="text-sm text-destructive">{submitError}</p>
161	        )}
162	        <Button onClick={handleSubmit} disabled={submitting || !selectedModelId || !reason.trim()}>
163	          {submitting ? "提交中..." : "提交申请"}
164	        </Button>
165	      </div>
166	    </div>
167	  );
168	}
