1	"use client";
2	
3	import { useEffect, useState } from "react";
4	import Link from "next/link";
5	import { useAuth } from "@/lib/auth-context";
6	import { apiFetch, type PaginatedResponse } from "@/lib/api-client";
7	import { Button } from "@/components/ui/button";
8	
9	interface TicketItem {
10	  id: string;
11	  type: string;
12	  status: string;
13	  reason: string;
14	  createdAt: string;
15	  targetModel?: { modelName: string; brandName: string };
16	  targetAsset?: { id: string; model?: { modelName: string } };
17	}
18	
19	const TYPE_OPTIONS = [
20	  { value: "", label: "全部类型" },
21	  { value: "APPLY", label: "申领" },
22	  { value: "REPAIR", label: "报修" },
23	  { value: "RETURN", label: "归还" },
24	  { value: "TRANSFER", label: "调拨" },
25	];
26	
27	const STATUS_OPTIONS = [
28	  { value: "", label: "全部状态" },
29	  { value: "SUBMITTED", label: "已提交" },
30	  { value: "PENDING_MANAGER_1", label: "待主管审批" },
31	  { value: "PENDING_MANAGER_2", label: "待上级审批" },
32	  { value: "PENDING_IT", label: "待IT处理" },
33	  { value: "APPROVED", label: "已通过" },
34	  { value: "REJECTED", label: "已驳回" },
35	  { value: "IN_PROGRESS", label: "处理中" },
36	  { value: "COMPLETED", label: "已完成" },
37	  { value: "CANCELLED", label: "已取消" },
38	];
39	
40	export default function TicketsPage() {
41	  const { user } = useAuth();
42	  const [tickets, setTickets] = useState<TicketItem[]>([]);
43	  const [page, setPage] = useState(1);
44	  const [totalPages, setTotalPages] = useState(1);
45	  const [typeFilter, setTypeFilter] = useState("");
46	  const [statusFilter, setStatusFilter] = useState("");
47	  const [loading, setLoading] = useState(true);
48	  const [error, setError] = useState("");
49	
50	  const fetchTickets = async (p: number) => {
51	    setLoading(true);
52	    setError("");
53	    try {
54	      const res = await apiFetch<PaginatedResponse<TicketItem>>("/api/tickets", {
55	        params: { page: p, pageSize: 20, type: typeFilter || undefined, status: statusFilter || undefined },
56	      });
57	      setTickets(res.data);
58	      setTotalPages(res.pagination.totalPages);
59	      setPage(res.pagination.page);
60	    } catch (err) {
61	      setError(err instanceof Error ? err.message : "加载失败");
62	    } finally {
63	      setLoading(false);
64	    }
65	  };
66	
67	  useEffect(() => {
68	    fetchTickets(1);
69	  }, [typeFilter, statusFilter]);
70	
71	  const statusBadge = (status: string) => {
72	    const map: Record<string, string> = {
73	      SUBMITTED: "bg-gray-100 text-gray-800 dark:bg-gray-900/30 dark:text-gray-400",
74	      PENDING_MANAGER_1: "bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-400",
75	      PENDING_MANAGER_2: "bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-400",
76	      PENDING_IT: "bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400",
77	      APPROVED: "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400",
78	      REJECTED: "bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400",
79	      IN_PROGRESS: "bg-purple-100 text-purple-800 dark:bg-purple-900/30 dark:text-purple-400",
80	      COMPLETED: "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400",
81	      CANCELLED: "bg-gray-100 text-gray-800 dark:bg-gray-900/30 dark:text-gray-400",
82	    };
83	    const label: Record<string, string> = {
84	      SUBMITTED: "已提交",
85	      PENDING_MANAGER_1: "待主管审批",
86	      PENDING_MANAGER_2: "待上级审批",
87	      PENDING_IT: "待IT处理",
88	      APPROVED: "已通过",
